  ('promotion-7fec267e-moex-00135', 'promotion-7fec267e', 'promotion-7fec267e-moex-110-3a7b2121', 'sub-promotion-7fec267e-03', NULL, 'single_choice', '西元 2000年以來，治理（governance）的觀念深刻影響公部門的運作，關於治理內涵之敘述， 下列何者錯誤？', '["公、私部門的界線越趨模糊", "強調利害關係人（stakeholder）之間的互動", "層級節制（hierarchy）與權威不復存在", "除了效率外，強調更多價值，如透明、課責、廉潔"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:41+00:00", "source_pdf_sha1": "642c105f3438", "answer_pdf_sha1": "44597aef9ae9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "101", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "一般行政"}'::jsonb, NULL),
